prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  FILTER(CONTAINS(LCASE(STR(?model)), "4e8df28e6d9f4afe970d06522542e830") || 
         CONTAINS(LCASE(?originalId), "4e8df28e6d9f4afe970d06522542e830") ||
         CONTAINS(LCASE(?normalizedId), "4e8df28e6d9f4afe970d06522542e830"))
  OPTIONAL { ?model bbo:name ?modelName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?source ?target ?sourceName ?targetName WHERE {
  ?edge a bbo:SequenceFlow .
  OPTIONAL { ?edge bbo:has_sourceRef ?source . }
  OPTIONAL { ?edge bbo:has_targetRef ?target . }
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  FILTER(CONTAINS(STR(?source), "sid-7A310B93-7314-4BBC-86D7-667A0A9B4464") ||
         CONTAINS(STR(?target), "sid-7A310B93-7314-4BBC-86D7-667A0A9B4464") ||
         CONTAINS(STR(?source), "sid-5AB935B2-C85F-40E0-9634-5E19FDB6C487") ||
         CONTAINS(STR(?target), "sid-5AB935B2-C85F-40E0-9634-5E19FDB6C487"))
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?sourceId ?targetId ?sourceName ?targetName WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_dd7a27c7_a916_41b5_a596_d1a83c30cef2> .
  OPTIONAL { ?edge bbo:has_sourceRef ?source . }
  OPTIONAL { ?edge bbo:has_targetRef ?target . }
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  BIND(REPLACE(STR(?source), "^.*/", "") AS ?sourceId)
  BIND(REPLACE(STR(?target), "^.*/", "") AS ?targetId)
}
ORDER BY ?sourceName ?targetName
LIMIT 100

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
